// B1-PROCESS — Montar objeto completo do processo + buscar template do modelo
const https = require('https');
const SUPA_HOST = 'qdivfairxhdihaqqypgb.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';

function supaGet(path) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname: SUPA_HOST, path, method: 'GET',
      headers: { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json' }
    }, (res) => {
      let data = '';
      res.on('data', c => { data += c; });
      res.on('end', () => {
        if (res.statusCode >= 400) return reject(new Error('SUPA ' + res.statusCode + ': ' + data.substring(0, 300)));
        try { resolve(data ? JSON.parse(data) : null); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
}

const ctx = $('B1-Prep').item.json;
const processosRaw = $('B1-HTTP-Processo').item.json;
const analisesResp = $('B1-HTTP-AnaliseAnt').item.json;
const analisesRaw = analisesResp?.body ?? analisesResp;

const processos = Array.isArray(processosRaw) ? processosRaw : [processosRaw];
const processo = processos[0];
if (!processo || !processo.id) throw new Error('Processo não encontrado: ' + ctx.processo_id);

const empresa = processo.empresa || {};
const categoria = empresa.categoria || {};
const analises = Array.isArray(analisesRaw) ? analisesRaw : [];
const analise_anterior = analises[0] || null;

// Buscar template do modelo se modelo_grupo_id foi fornecido
let modelo_template = null;
if (ctx.modelo_grupo_id) {
  try {
    const grupos = await supaGet('/rest/v1/olivia_modelos_grupo?id=eq.' + ctx.modelo_grupo_id + '&select=id,nome,active_version_id');
    const grupo = Array.isArray(grupos) && grupos[0] ? grupos[0] : null;
    if (grupo && grupo.active_version_id) {
      const versoes = await supaGet('/rest/v1/olivia_modelos_peticao?id=eq.' + grupo.active_version_id + '&select=id,nome,conteudo_template,instrucoes_ia');
      const versao = Array.isArray(versoes) && versoes[0] ? versoes[0] : null;
      if (versao && versao.conteudo_template) {
        modelo_template = { id: versao.id, nome: versao.nome, conteudo_template: versao.conteudo_template, instrucoes_ia: versao.instrucoes_ia || null };
      }
    }
  } catch(e) {
    // Silently fail — análise continua sem template
  }
}


// Buscar restrições de crédito do processo
let restricoes_ativas = [];
let restricao_principal = null;
try {
  const restricoes = await supaGet('/rest/v1/restricoes_credito?processo_id=eq.' + ctx.processo_id + '&order=created_at.desc&limit=5&select=orgao_nome,valor,contrato,data_inclusao,data_vencimento,status');
  if (Array.isArray(restricoes) && restricoes.length > 0) {
    restricoes_ativas = restricoes;
    restricao_principal = restricoes[0];
  }
} catch(e) {
  // Tabela pode não existir — silently fail
}
return [{
  json: {
    analise_id: ctx.analise_id,
    organizacao_id: ctx.organizacao_id,
    request_id: ctx.request_id,
    user_id: ctx.user_id,
    processo_id: ctx.processo_id,
    tipo_analise: ctx.tipo_analise,
    arquivos_input: ctx.arquivos_input || [],
    contexto_adicional: ctx.contexto_adicional || '',
    modelo_grupo_id: ctx.modelo_grupo_id || null,
    modelo_template: modelo_template,
    processo: {
      id: processo.id,
      numero_cnj: processo.numero_cnj,
      numero_processo: processo.numero_processo,
      tipo_processo: processo.tipo_processo,
      objeto: processo.objeto,
      valor_causa: processo.valor_causa,
      grau: processo.grau,
      polo_representado: processo.polo_representado,
      ia_resumo: processo.ia_resumo,
      chance_sucesso_ia: processo.chance_sucesso_ia,
      valor_condenacao: processo.valor_condenacao,
      restricao_orgao_nome: processo.restricao_orgao_nome || null,
      restricao_valor: processo.restricao_valor || null,
      restricao_contrato: processo.restricao_contrato || null,
      restricao_data: processo.restricao_data || null
    },
    empresa: {
      id: empresa.id,
      nome: empresa.nome,
      cnpj: empresa.cnpj,
      razao_social: empresa.razao_social,
      segmento: empresa.segmento,
      analise_ia: empresa.analise_ia
    },
    categoria_id: empresa.categoria_id,
    categoria_nome: categoria.nome || 'Geral',
    cliente: processo.cliente || {},
    advogado: processo.advogado || {},
    comarca: processo.comarca || {},
    analise_anterior: analise_anterior,
    ia_resumo_existente: processo.ia_resumo,
    restricoes_ativas: restricoes_ativas,
    restricao_principal: restricao_principal,
    chance_sucesso_existente: processo.chance_sucesso_ia
  }
}];

// B2-PROCESS — Processar tags e blocos
const ctx = $('B1-Process').item.json;
const result = $('B2-HTTP-Tags').item.json;

let tags = [];
let blocos = [];
let categoria_nome = ctx.categoria_nome || 'Geral';

if (result && !result.code) {
  tags = result.tags || [];
  blocos = (result.blocos || []).slice(0, 50);
  categoria_nome = result.categoria_nome || categoria_nome;
}

// RAG query dinâmica
const tagTexts = tags.map(t => t.nome).join(' ');
const ragQuery = ([tagTexts, ctx.empresa?.nome || '', ctx.processo?.tipo_processo || '']
  .filter(Boolean).join(' ') || 'restricao credito negativacao indevida direito consumidor').substring(0, 500);

// Flag de erro: modelo sem tags E sem blocos
const semTagsEBlocos = tags.length === 0 && blocos.length === 0;

return [{
  json: {
    ...ctx,
    categoria_nome,
    tags,
    blocos,
    total_tags: tags.length,
    total_blocos: blocos.length,
    rag_query: ragQuery,
    _sem_tags_e_blocos: semTagsEBlocos
  }
}];

// B3-PROCESS — Processar playbook
const ctx = $('B2-Process').item.json;
const results = $('B3-HTTP-Playbook').item.json;
const arr = Array.isArray(results) ? results : (results && !results.code ? [results] : []);
const playbook = arr[0] || null;

return [{
  json: {
    ...ctx,
    playbook: (playbook && playbook.nome) ? {
      encontrado: true,
      nome: playbook.nome,
      instrucoes: playbook.instrucoes || '',
      match_level: playbook.match_level
    } : {
      encontrado: false,
      nome: 'Genérico',
      instrucoes: null,
      match_level: null
    }
  }
}];

// Recuperar contexto - D1 pode não ter rodado (bypass sem docs)
let ctx;
try {
  ctx = $('D1-ConsolidarDocs').item.json;
} catch(e) {
  // Bypass: sem docs, pegar contexto de B3-Process com campos extras
  const b3ctx = $('B3-Process').item.json;
  ctx = {
    ...b3ctx,
    docs_extraidos: [],
    total_docs: 0,
    qualidade_media: 0
  };
}
return [{json: ctx}];

// D4b — Agregar resultados RAG (fullResponse ou array)
const items = $input.all();

let ragResults = [];
for (const item of items) {
  const j = item.json;
  // fullResponse: j.body é o array de resultados
  if (j.body !== undefined) {
    const body = Array.isArray(j.body) ? j.body : [];
    ragResults = ragResults.concat(body);
  } else if (j.id !== undefined) {
    // Item direto do RAG
    ragResults.push(j);
  }
}

// Retornar sempre 1 item
return [{ json: { _rag_results: ragResults } }];

// C8 — Consolidar resultado de Vision fallback no contexto
// Fluxo: C5b[needs_vision] → C6-Gemini → C7-Mistral → C8
// C8 sempre recebe após C7 (que foi chamado após C6)
const ctx = $('C5-FormatPDF').item.json;

let textoVision = '';
let modelUsed = 'vision_fallback';

// 1. Tentar Gemini primeiro
try {
  const geminiOut = $('C6-GeminiVision').item.json;
  if (geminiOut?.candidates?.[0]?.content?.parts?.[0]?.text) {
    textoVision = geminiOut.candidates[0].content.parts[0].text.substring(0, 20000);
    modelUsed = 'gemini-2.0-flash';
  }
} catch(e) {
  // Gemini falhou — continua para Mistral
}

// 2. Tentar Mistral se Gemini não retornou texto
if (!textoVision) {
  try {
    const mistralOut = $input.item.json; // C8 recebe direto de C7
    if (mistralOut?.pages?.[0]?.markdown) {
      // Mistral OCR retorna pages[].markdown
      textoVision = mistralOut.pages.map(p => p.markdown || '').join('\n\n').substring(0, 20000);
      modelUsed = 'mistral-ocr-latest';
    } else if (mistralOut?.text) {
      textoVision = mistralOut.text.substring(0, 20000);
      modelUsed = 'mistral-ocr-latest';
    } else if (mistralOut?.choices?.[0]?.message?.content) {
      textoVision = mistralOut.choices[0].message.content.substring(0, 20000);
      modelUsed = 'mistral-ocr-latest';
    }
  } catch(e) {
    // Mistral também falhou
  }
}

// 3. Fallback: usar texto original (mesmo que baixa qualidade)
if (!textoVision) {
  textoVision = ctx.doc_atual?.extracted?.texto_completo || '(extração vision falhou — sem texto disponível)';
  modelUsed = 'pdf_native_fallback';
}

const qualidade = textoVision.length > 500 ? 85 : textoVision.length > 100 ? 50 : 15;

return [{
  json: {
    ...ctx,
    doc_atual: {
      ...ctx.doc_atual,
      extracted: {
        texto_completo: textoVision,
        qualidade_extracao: qualidade,
        method: modelUsed
      },
      extraction_model: modelUsed,
      qualidade_extracao: qualidade
    },
    needs_vision: false
  }
}];
